const DataControls = () => {
  return (
    <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-200 space-y-4">
      <h3 className="font-bold text-gray-700">Données</h3>
      <div className="grid grid-cols-2 gap-2">
        <button className="text-xs bg-blue-50 hover:bg-blue-100 text-blue-600 p-2 rounded border border-blue-200">
          📥 Import JSON
        </button>
        <button className="text-xs bg-purple-50 hover:bg-purple-100 text-purple-600 p-2 rounded border border-purple-200">
          📤 Export BSON
        </button>
      </div>
      <p className="text-[10px] text-gray-400 italic">
        Utilisez ces outils pour réinitialiser la base de démo.
      </p>
    </div>
  );
};
